#nullable enable // autogenerated

using PVZEngine;
using PVZEngine.Base;

namespace MVZ2.Metas
{
    public class AlmanacVariableReferenceProperty : AlmanacVariableReference
    {
        public string propertyName;
        public NamespaceID? target;
        public string? targetType;

        public AlmanacVariableReferenceProperty(string propertyName)
        {
            this.propertyName = propertyName;
        }
        public override object? GetVariableValue(AlmanacVariableContext context)
        {
            var main = context.main;
            var definitionType = context.currentDefinitionType;
            var definitionID = context.currentDefinitionID;
            if (!string.IsNullOrEmpty(targetType))
            {
                definitionType = targetType;
            }
            if (NamespaceID.IsValid(target))
            {
                definitionID = target;
            }
            var definition = main.Game.GetDefinition<Definition>(definitionType, definitionID);
            if (definition != null)
            {
                var key = PropertyMapper.ConvertFromName(propertyName);
                return definition.GetPropertyObject(key);
            }
            return null;
        }
    }
}
